     1→// ==================== CORE TYPES ====================
     2→
     3→import type { CustomFieldsMap } from './customFields';
     4→
     5→export type ViewMode = 'monthly' | 'weekly' | 'daily' | 'agenda';
     6→export type TaskStatus = 'backlog' | 'todo' | 'inprogress' | 'review' | 'done';
     7→export type TaskPriority = 'low' | 'medium' | 'high';
     8→
     9→// ==================== WIDGET DATA TYPES ====================
    10→
    11→export interface CalendarEvent {
    12→  id: string;
    13→  title: string;
    14→  description?: string;
    15→  startTime?: string; // "14:00" (24-hour format)
    16→  endTime?: string;   // "15:30"
    17→  isAllDay?: boolean; // default true if no times specified
    18→
    19→  // Recurrence
    20→  recurrence?: {
    21→    frequency: 'daily' | 'weekly' | 'monthly' | 'yearly';
    22→    interval: number; // e.g., every 2 weeks
    23→    daysOfWeek?: number[]; // 0=Sun, 1=Mon, etc. (for weekly)
    24→    dayOfMonth?: number; // 1-31 (for monthly)
    25→    endType: 'never' | 'after' | 'until';
    26→    endCount?: number; // if endType='after'
    27→    endDate?: string; // if endType='until' (YYYY-MM-DD)
    28→  };
    29→  recurrenceId?: string; // For recurring event instances (parent event ID)
    30→  recurrenceException?: boolean; // True if this instance was edited
    31→
    32→  // Multi-day
    33→  endDate?: string; // YYYY-MM-DD (if different from startDate)
    34→
    35→  // Reminders
    36→  reminders?: number[]; // Minutes before event (e.g., [15, 60])
    37→
    38→  // Location
    39→  location?: string;
    40→
    41→  // Multi-day rendering flags (internal, not persisted)
    42→  _isMultiDayPart?: boolean;
    43→  _isMultiDayFirst?: boolean;
    44→  _isMultiDayLast?: boolean;
    45→}
    46→
    47→export interface CalendarState {
    48→  events: Record<string, CalendarEvent[]>; // dateKey -> array of events
    49→  viewMode: ViewMode;
    50→  currentDate: Date;
    51→}
    52→
    53→export type DependencyType =
    54→  | 'finish-to-start'  // Task B starts when A finishes (default)
    55→  | 'start-to-start'   // Task B starts when A starts
    56→  | 'finish-to-finish' // Task B finishes when A finishes
    57→  | 'start-to-finish'; // Task B finishes when A starts (rare)
    58→
    59→export interface TaskDependency {
    60→  taskId: string;           // ID of dependent task
    61→  type: DependencyType;     // Type of dependency
    62→  lag: number;              // Lag time in days (can be negative for lead)
    63→}
    64→
    65→// Phase 1.4: Baseline snapshot for task (stored in project baseline)
    66→export interface BaselineTask {
    67→  id: string;
    68→  startDate: string | null;
    69→  dueDate: string | null;
    70→  progress: number;
    71→}
    72→
    73→// Phase 1.4: Project baseline snapshot
    74→export interface ProjectBaseline {
    75→  setAt: string;            // ISO date when baseline was set
    76→  tasks: BaselineTask[];    // Snapshot of all tasks at baseline time
    77→}
    78→
    79→// Phase 1.4: Variance status for baseline comparison
    80→export type VarianceStatus = 'ahead' | 'behind' | 'on-track';
    81→
    82→// Phase 3.1: Team member for task assignment
    83→export interface Member {
    84→  id: string;
    85→  name: string;
    86→  email?: string;
    87→  initials: string;        // Auto-generated from name
    88→  avatarColor: string;     // Hex color for avatar background
    89→  createdAt: string;       // ISO date
    90→}
    91→
    92→// Phase 3.2: File attachment for tasks
    93→export interface TaskAttachment {
    94→  id: string;
    95→  taskId: string;
    96→  filename: string;
    97→  fileType: string;        // MIME type (e.g., "image/png", "application/pdf")
    98→  fileSize: number;        // Bytes
    99→  dataUrl: string;         // Base64 data URI
   100→  uploadedAt: string;      // ISO date
   101→  uploadedBy?: string;     // Future: member ID
   102→}
   103→
   104→// Phase 4: Column definition for custom Kanban columns
   105→export interface KanbanColumn {
   106→  id: string;              // e.g., "backlog", "todo", or UUID for custom
   107→  title: string;           // e.g., "Backlog", "In Progress"
   108→  color: string;           // Tailwind class: "bg-status-info"
   109→  order: number;           // For drag-drop reordering
   110→  wipLimit?: number;       // Optional WIP constraint (e.g., 5 tasks max)
   111→}
   112→
   113→// Phase 4: Checklist item for subtasks
   114→export interface ChecklistItem {
   115→  id: string;
   116→  text: string;
   117→  completed: boolean;
   118→  order: number;
   119→  createdAt: string;       // ISO date
   120→}
   121→
   122→// Phase 5: Subtask - Rich nested tasks within a card
   123→export interface Subtask {
   124→  id: string;
   125→  parentTaskId: string;
   126→  title: string;
   127→  description?: string;
   128→  completed: boolean;
   129→  priority?: TaskPriority;
   130→  dueDate?: string;       // YYYY-MM-DD
   131→  order: number;          // For manual sorting
   132→  createdAt: string;      // ISO date
   133→  completedAt?: string;   // ISO date (when marked complete)
   134→}
   135→
   136→// Phase 5: Simple task dependency (blocks/blocked-by)
   137→export interface SimpleTaskDependency {
   138→  id: string;
   139→  sourceTaskId: string; // Task that blocks
   140→  targetTaskId: string; // Task that is blocked
   141→  createdAt: string;    // ISO date
   142→}
   143→
   144→// Phase 4: Comment for task discussions
   145→export interface TaskComment {
   146→  id: string;
   147→  taskId: string;
   148→  text: string;            // Markdown supported
   149→  author: string;          // For future: user ID, for now: "You"
   150→  createdAt: string;       // ISO date
   151→  updatedAt?: string;      // ISO date (if edited)
   152→}
   153→
   154→// Phase 4: Activity log entry for tracking changes
   155→export interface ActivityLogEntry {
   156→  id: string;
   157→  timestamp: string;       // ISO date
   158→  action: 'created' | 'updated' | 'moved' | 'commented' | 'checklist_updated';
   159→  field?: string;          // e.g., "status", "priority"
   160→  oldValue?: string;
   161→  newValue?: string;
   162→  userId?: string;         // For future: "You" for now
   163→}
   164→
   165→// Undo system: History entry for undoing destructive actions
   166→export interface UndoHistoryEntry {
   167→  id: string;              // Unique ID for this action
   168→  timestamp: string;       // ISO date
   169→  action: 'deleteColumn' | 'replaceAllColumns' | 'deleteTask' | 'bulkDelete';
   170→  description: string;     // Human-readable: "Deleted column 'In Progress'"
   171→  previousState: {
   172→    columns: KanbanColumn[];
   173→    tasks: Task[];
   174→  };
   175→}
   176→
   177→export type EffortEstimate = 1 | 2 | 3 | 5 | 8 | 13; // Story points (Fibonacci)
   178→export type CustomStatus = 'in-review' | 'testing' | 'deployed' | 'blocked'; // Beyond base status
   179→
   180→// Phase 4: Card templates for quick task creation
   181→export interface CardTemplate {
   182→  id: string;
   183→  name: string;
   184→  icon: string;
   185→  description: string;           // Pre-filled description
   186→  defaultPriority: TaskPriority;
   187→  defaultTags: string[];
   188→  defaultColumn?: string;        // Optional default column
   189→  isBuiltIn: boolean;            // System templates vs user-created
   190→}
   191→
   192→export interface TimeTracking {
   193→  estimated?: number;           // Estimated hours
   194→  actual: number;               // Actual hours spent
   195→  activeTimerStart?: string;    // ISO date (null = timer not running)
   196→  timerHistory: Array<{         // Time tracking history log
   197→    id: string;
   198→    startTime: string;          // ISO date
   199→    endTime: string;            // ISO date
   200→    duration: number;           // Seconds
   201→  }>;
   202→}
   203→
   204→export interface Task {
   205→  id: string;
   206→  title: string;
   207→  description: string;
   208→  status: TaskStatus;
   209→  created: string; // ISO date string
   210→  startDate: string | null; // Date string YYYY-MM-DD
   211→  dueDate: string | null; // Date string YYYY-MM-DD
   212→  priority: TaskPriority;
   213→  tags: string[];
   214→  order?: number; // Position within status column for drag-drop
   215→
   216→  // ENHANCED PM FIELDS:
   217→  dependencies?: TaskDependency[]; // Tasks this depends on
   218→  estimatedHours?: number;         // For resource planning
   219→  actualHours?: number;            // For EVM calculations
   220→  progress?: number;               // 0-100 percentage complete
   221→  isMilestone?: boolean;           // True for milestone markers
   222→  assignedTo?: string;             // Resource ID
   223→  baseline?: {                     // Original plan for comparison
   224→    startDate: string;
   225→    dueDate: string;
   226→  };
   227→  isOnCriticalPath?: boolean;      // Calculated field
   228→
   229→  // PHASE 4 FIELDS:
   230→  checklist?: ChecklistItem[];     // Subtasks/checklist
   231→  comments?: TaskComment[];        // Discussion/comments
   232→  activityLog?: ActivityLogEntry[]; // Change history
   233→
   234→  // PHASE 5 FIELDS:
   235→  subtasks?: Subtask[];            // Rich nested tasks
   236→
   237→  // PHASE A (QUICK WINS) FIELDS:
   238→  archivedAt?: string;             // ISO date (when task was archived)
   239→  lastCompletedAt?: string;        // ISO date (when moved to "done" for auto-archive)
   240→  cardNumber?: number;             // Auto-incrementing card number (KAN-1, KAN-2, etc.)
   241→
   242→  // PHASE B (KANBAN PM) FIELDS:
   243→  effort?: EffortEstimate;         // Story points (1, 2, 3, 5, 8, 13)
   244→  customStatus?: CustomStatus;     // Additional status labels (in-review, testing, deployed, blocked)
   245→  timeTracking?: TimeTracking;     // Time tracking with history
   246→
   247→  // RECURRING TASKS FIELDS (P1):
   248→  recurrence?: {
   249→    frequency: 'daily' | 'weekly' | 'monthly' | 'yearly';
   250→    interval: number; // e.g., every 2 weeks
   251→    daysOfWeek?: number[]; // 0=Sun, 1=Mon, etc. (for weekly)
   252→    dayOfMonth?: number; // 1-31 (for monthly)
   253→    endType: 'never' | 'after' | 'until';
   254→    endCount?: number; // if endType='after'
   255→    endDate?: string; // if endType='until' (YYYY-MM-DD)
   256→    recurFromCompletion?: boolean; // If true, recur from completion date instead of due date (default: false)
   257→  };
   258→  recurrenceId?: string; // For recurring task instances (parent task ID)
   259→  recurrenceException?: boolean; // True if this instance was edited
   260→  isRecurringParent?: boolean; // True if this is the parent/template task
   261→  nextOccurrence?: string; // YYYY-MM-DD (calculated field)
   262→
   263→  // CUSTOM FIELDS (P2 #3):
   264→  customFields?: CustomFieldsMap; // Custom metadata fields (fieldId -> value)
   265→
   266→  // PHASE 3.1 FIELDS (TEAM COLLABORATION):
   267→  assignees?: string[];           // Array of member IDs assigned to this task
   268→
   269→  // PHASE 3.2 FIELDS (FILE ATTACHMENTS):
   270→  attachments?: TaskAttachment[]; // File attachments for this task
   271→
   272→  // PHASE 3.4 FIELDS (CARD COVERS):
   273→  coverMode?: 'fit' | 'fill'; // Cover image display mode (default: 'fit')
   274→}
   275→
   276→export interface KanbanState {
   277→  tasks: Task[];
   278→  columns: KanbanColumn[];         // Phase 4: Dynamic columns
   279→  // NOTE: dependencies moved to Task.dependencies (task-level instead of global)
   280→  archivedTasks?: Task[];          // Phase A: Archived tasks (separate from active)
   281→  nextCardNumber?: number;         // Phase A: Auto-incrementing counter for card numbers
   282→  visibleColumns?: number;         // Number of columns to show at once before scrolling (default: 5)
   283→  baseline?: ProjectBaseline | null; // Phase 1.4: Project baseline snapshot
   284→}
