   317→// ==================== TIME TRACKING TYPES ====================
   318→
   319→export interface TimeEntry {
   320→  id: string;
   321→  workspaceId: string;           // Always use default workspace for now
   322→  projectId?: string;            // Optional: Link to project
   323→  taskId?: string;               // Optional: Link to Kanban task
