   146→          endTime = new Date(date);
   147→          endTime.setHours(parseInt(timeParts[0]) || 0, parseInt(timeParts[1]) || 0, 0, 0);
   148→        }
   149→
   150→        // Calculate duration
   151→        if (durationIdx !== -1 && values[durationIdx]?.trim()) {
   152→          duration = parseInt(values[durationIdx].trim()) * 60; // Convert minutes to seconds
   153→        } else if (endTime) {
