                              ? 'bg-accent-magenta/50 dark:bg-accent-cyan/50'
                              : 'bg-border-light dark:bg-border-dark'
                          }`}
                          style={{ height: `${Math.max(heightPercent, 4)}%` }}
                          title={`${formatDuration(day.totalDuration, { showSeconds: false })}`}
                        />
                        <span className={`text-xs ${isToday ? 'font-bold text-accent-magenta dark:text-accent-cyan' : 'text-text-light-tertiary dark:text-text-dark-tertiary'}`}>
