                      />
                      <h4 className="text-base font-semibold text-text-light-primary dark:text-text-dark-primary truncate">
                        {project.name}
                      </h4>
                    </div>
                    {project.clientName && (
                      <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                        Client: {project.clientName}
                      </p>
                    )}
                  </div>

                  <div className="flex items-center gap-2 ml-4">
                    <button
                      onClick={() => handleToggleActive(project)}
                      className="p-2 rounded-buttonhover:bg-surface-light dark:hover:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:text-status-success transition-all duration-standard ease-smooth"
                      title="Unarchive project"
                    >
                      <FolderOpen className="w-4 h-4" />
