                      onClick={() => handleDelete(project.id)}
                      disabled={deletingId === project.id}
                      className="p-2 rounded-buttonhover:bg-surface-light dark:hover:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:text-status-error transition-all duration-standard ease-smooth disabled:opacity-50"
                      title="Delete project"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

