/**
 * Export time entries to CSV format
 */
export function exportTimeEntriesToCSV(entries: TimeEntry[], projects: { id: string; name: string }[]): ExportResult {
  try {
    if (entries.length === 0) {
      return { success: false, error: 'No entries to export' };
    }

    // Create project lookup map
    const projectMap = new Map(projects.map(p => [p.id, p.name]));

    // CSV Headers
    const headers = [
      'Date',
      'Start Time',
      'End Time',
      'Duration (minutes)',
      'Description',
      'Project',
      'Tags',
      'Notes',
      'Is Billable',
      'Hourly Rate',
      'Billable Amount'
    ];

    // Format entries as CSV rows
    const rows = entries.map(entry => {
      const startDate = new Date(entry.startTime);
      const endDate = entry.endTime ? new Date(entry.endTime) : null;

      // Calculate billable amount
      const hours = entry.duration / 3600;
      const rate = entry.hourlyRate || projects.find(p => p.id === entry.projectId)?.hourlyRate || 0;
      const billableAmount = entry.billable && rate > 0 ? (hours * rate).toFixed(2) : '0.00';

      return [
        startDate.toISOString().split('T')[0], // Date (YYYY-MM-DD)
        startDate.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: false }), // Start Time (HH:MM)
        endDate ? endDate.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: false }) : '', // End Time
        Math.round(entry.duration / 60).toString(), // Duration in minutes
        escapeCSV(entry.description || ''),
        escapeCSV(projectMap.get(entry.projectId || '') || 'No Project'),
        escapeCSV((entry.tags || []).join(', ')),
        escapeCSV(entry.notes || ''),
        entry.billable ? 'Yes' : 'No', // Is Billable
        rate > 0 ? rate.toFixed(2) : '', // Hourly Rate
        billableAmount // Billable Amount
      ];
    });

    // Combine headers and rows
    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.join(','))
    ].join('\n');

    return { success: true, data: csvContent };
  } catch (error) {
    return { success: false, error: String(error) };
  }
}

